window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2020>1","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"BASIC CONCEPTS : MEANING AND IMPORTANCE OF AGRICULTURE","question":"A nation exports agricultural produce mainly to","images":[],"options":{"A":"Provide food","B":"Create employment","C":"Earn foreign exchange","D":"Provide raw material"},"answer":"C","explanation":"The major reason nation produce is to earn foreign exchange . Foreign exchange simply involves converting the agriculture produce to something of value obtain from another country.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>2","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Quarantine measures in agriculture are aimed at","images":[],"options":{"A":"Regulating cost of importation of crops and animals","B":"Preventing the introduction of pest and disease","C":"Maintaining genetic purity of crops and animals","D":"Introducing new varieties of crops and breeds of animals"},"answer":"B","explanation":"Quarantine measures in agriculture are primarily aimed at preventing the introduction of pests and diseases. This is done to protect local agriculture from the potential negative impact of foreign pests and diseases that could be introduced through the importation of crops and animals. Quarantine measures may include inspections, treatments, and restrictions on the importation of certain agricultural products.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>3","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Which of the following statement is not true about farming in west Africa","images":[],"options":{"A":"Farm labour is highly inefficient","B":"Farm workers are poorly paid","C":"Getting reliable labour is difficult","D":"Mechanization is fully adopted"},"answer":"D","explanation":"The statement that 'Mechanization is fully adopted' is not true about farming in West Africa. While there has been some progress in the adoption of mechanization in farming in West Africa, it is not fully adopted due to factors such as cost, lack of access to modern machinery, and lack of knowledge and skills in operating modern farming equipment. The other statements are generally true as farm labour is often inefficient and poorly paid, and getting reliable labour can be difficult.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>4","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Mechanical power is not usually required in","images":[],"options":{"A":"Soil tillage","B":"fertilizer application","C":"Staking of yams","D":"Planting of seeds"},"answer":"C","explanation":"In staking of yam, you manually erect a stick to give it vines space to crawl around . staking is done to elevate the yam above the ground","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>5","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The illustrated equipment is called","images":["data:image/png;base64,"],"options":{"A":"arrow","B":"Harpoon","C":"Wooden peg","D":"ranging pole"},"answer":"D","explanation":"The ilustrated equipment is called ranging pole. it is  a surveying equipment for making striaght lines and marking stations","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>6","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The illustrated equipment is used for","images":["data:image/png;base64,"],"options":{"A":"making drills","B":"marking stations","C":"marking chain lengths","D":"making holes for transplanting"},"answer":"B","explanation":"A ranging pole is a surveying tool used to mark specific points or stations on the ground during land surveying and construction projects.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>7","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM PLANNING","question":"Calculate the area of the farmland.","images":["data:image/png;base64,"],"options":{"A":"0.32ha","B":"0.36ha","C":"0.4ha","D":"0.52ha"},"answer":"B","explanation":"The diagram / farmland given is a trapezium  Area of a trapezium = 1/2(sum of parallel sides) height  Area = 1/2(70+90)45   = 80(45) = 3600m2  Recall : 1 ha = 104m2  x = 3600m2  x = 0.36ha","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2020>8","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM PLANNING","question":"The major objective of a farm planing is to","images":[],"options":{"A":"maximize the use of available resources","B":"control insects pests of crops","C":"Control diseases among animals","D":"reduce losses due to natural disasters"},"answer":"A","explanation":"The major objective of farm planning is to maximize the use of available resources. Farm planning is a decision-making process in the farm business which involves organization and management of resources to achieve the farm's objectives. The main goal is to ensure the best use of these resources, considering the farmer's business strategy and external factors like market conditions, government regulations, and available technology.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>9","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Which factor of production has he following charateristics?  I. Free gift of nature  II. Limited in supply  III. Immobile","images":[],"options":{"A":"Land","B":"labour","C":"capital","D":"Entrepreneur"},"answer":"A","explanation":"The factor of production that is a free gift of nature, limited in supply, and immobile is Land. Land in economics includes all natural resources like minerals, water bodies, fertile soil, air, sunlight, etc. It is considered a free gift of nature as it is not man-made. It is limited in supply as the total land area of the earth is fixed. It is immobile as it cannot be moved from one place to another.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>10","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"Igneous rocks can easily be identified through their","images":[],"options":{"A":"Glassy appearance","B":"coarse texture","C":"Stratisfied layers","D":"Fossil contents"},"answer":"A","explanation":"Igneous rocks can easily be identified through their glassy appearance. Igneous rocks are formed from the solidification of magma or lava. The rapid cooling of lava or magma results in a glassy texture. Other characteristics of igneous rocks like coarse texture or the presence of stratified layers or fossil contents are not definitive as they can also be found in other types of rocks.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>11","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"Water which rises above the water table in the soil and is held medium pores between soil particles by surface tension is","images":[],"options":{"A":"Hygroscopic water","B":"Gravitational water","C":"Capillary water","D":"Percolating water"},"answer":"C","explanation":"This describes capilliary water, capillary water is held in the soil because the surface tension properties(Cohesion and adhesion) of the soil micropores are strong than the force of gravity","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>12","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"An oven dried soil sample of mass 8g had a mass of 1.6g after it was completely burnt. Determine the percentage of humus in the soil","images":[],"options":{"A":"6.4%","B":"9.6%","C":"20%","D":"80%"},"answer":"D","explanation":"Parameters given : mass of soil = 8g  Mass of after burning = 1.6g  Mass of humus = 6.4g  % of humus = 6.4/8 x 100 = 80%","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>13","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The deficiency of nitrogen in a maize plant can be corrected by applying","images":[],"options":{"A":"Potassium chloride","B":"Muriate of potash","C":"Sulphate of ammonia","D":"Calcium carbonate"},"answer":"C","explanation":"Fertilizers like ammonium phosphate and sulphate of ammonia can be used to replenish nitrogen deficiency in plants","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>14","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"The structure of sandy soils can be described as","images":[],"options":{"A":"Platy","B":"crumby","C":"Single-grained","D":"Blocky"},"answer":"C","explanation":"Sandy soils are described as single-grained. This is because they have large, coarse particles which are loosely packed and do not stick together. This gives the soil a single-grained structure.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>15","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"year 1 year 2 year 3 year 4Plot 1 yam groundnut maizecowpeaPlot 2 Groundnut maize cowpea yamPlot  3 maize  cowpea yam GroundnutPlot 4 cowpea yam Groundnut Maize    The cropping system illustrated in the table is","images":[],"options":{"A":"Mixed cropping","B":"Crop rotation","C":"Shiting cultivation","D":"Land rotation"},"answer":"B","explanation":"The farming/planting system illustrated in the diagram is crop rotation . crop rotation is the practical/system of growing a series of different typrs of crop in the same area a sequence of growing seasons .","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>16","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"year 1 year 2 year 3 year 4Plot 1 yam groundnut maizecowpeaPlot 2 Groundnut maize cowpea yamPlot  3 maize  cowpea yam GroundnutPlot 4 cowpea yam Groundnut Maize  Which of the following crop can conveniently replace maize in the table?","images":[],"options":{"A":"Cassava","B":"Cashew","C":"Mango","D":"Millet"},"answer":"A","explanation":"Maize is an annual crop, so it has to be replaced with an annual crop. The annual crop in the ptions is cassava","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>17","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"The following bacteria are important in the nitrogen cycle except","images":[],"options":{"A":"Bacillus","B":"Nitrobacter","C":"Nitrosomonas","D":"Rhizobium"},"answer":"A","explanation":"Bacillus is not important in the nitrogen cycle. In the nitrogen cycle , nitrosonomas converts ammonia to nitrates and nitrobacter converts nitrites  to nitrates. What rhizobium does is to fix nitrogen after becoming established inside the root nodules of legumes.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>18","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Determine the ratio of nutrient in NPK 5-10-15","images":[],"options":{"A":"1:2:2","B":"1:2:3","C":"1:3:1","D":"2:1:3"},"answer":"B","explanation":"In NPK 5-10-15, there are nitrogen atoms, 10 phosphorus atoms and 15 potassium atom  Ratio = 5:10:15 = 1:2:3","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>19","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Which of following methods of irrigation is most efficient in term of water conversation ?","images":[],"options":{"A":"Flood irrigation","B":"Furrow irrigation","C":"Border irrigation","D":"Drip irrigation"},"answer":"D","explanation":"Drip irrigation is a type of micro-irriation systm that has the potential to save water and nutrients by allowing water to drip slowly to the roots of plants either from above the soil surface or buried below the surface.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>20","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Which of the following crops is dicotyledonous ?","images":[],"options":{"A":"Zea mays","B":"Oryza sativa","C":"Elaeis guineensis","D":"Vigna unguiculata"},"answer":"D","explanation":"Dicotyledonous plants are those that start with two embryonic leaves or cotyledons.  Vigna unguiculata , also known as cowpea, is a dicotyledonous plant.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>21","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"Crop which grow and mature within few weeks of their cultivation are called","images":[],"options":{"A":"annual crops","B":"ephemeral crops","C":"perennial crops","D":"Biennial crops"},"answer":"B","explanation":"Ephemeral crops are crop that grow and reproduce very quickly to take advantage of the optial conditions","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>22","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"If the yield of cowpea is 750kg per hectare, calculate the yield of cowpea from a 20 hectare farm.","images":[],"options":{"A":"7500 kg","B":"15000kg","C":"22500","D":"37000kg"},"answer":"B","explanation":"750kg = 1 hectare   x = 20 hectare  750/x = 1/20  x = 15000kg","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>23","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following statements about threshing of rice are true?  I. Rice grains are separated from the panicle   II. Breakage of some grains could occur  III. The grains are polished","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I,II and III"},"answer":"A","explanation":"Threshing of rice involves separating the rice grains from the panicle, which is the part of the plant that holds the grains. During this process, some grains could break. However, the grains are not polished during threshing. Polishing is a separate process that happens after threshing and hulling, where the outer layer of the rice grain is removed to make it white and shiny. Therefore, statements I and II are true, while statement III is not.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>24","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"An important reason for staking yam is to","images":[],"options":{"A":"expose the leaves to sunlight","B":"prevent water logging on the farm","C":"enhance the formation of leaves","D":"expose the flowers to pollination"},"answer":"A","explanation":"Staking yam is done to support the plant as it grows and to expose the leaves to sunlight. Sunlight is essential for photosynthesis, a process by which plants make food. Staking does not prevent water logging on the farm, enhance the formation of leaves, or expose the flowers to pollination. Therefore, the correct answer is to expose the leaves to sunlight.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>25","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"A crop that can be propagated by stem cutting is","images":[],"options":{"A":"plantain","B":"pepper","C":"cassava","D":"carrot"},"answer":"C","explanation":"Cassava is propagated by cutting by planting pieces of stem,the roots of cassava are used for making a new plantation and thus all harvest can be eaten or sold.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>26","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Which of the following diseases of tomato is caused by a nematode?","images":[],"options":{"A":"Fusarium","B":"Root knot","C":"Leaf spot","D":"Leaf curl"},"answer":"B","explanation":"The root knot disease in tomatoes is caused by a nematode. Nematodes are microscopic, worm-like animals that live in the soil. The root knot nematode (Meloidogyne spp.) is a common problem in tomato plants. The nematodes enter the roots of the plants and cause the roots to form galls or 'knots' where the nematodes feed and reproduce. This disrupts the plant's ability to take up water and nutrients, leading to stunted growth and reduced yield.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>27","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The yield of cocoa trees is not influenced by","images":[],"options":{"A":"pest infestation","B":"fertilizer application","C":"method of harvesting","D":"method of soil tilage"},"answer":"D","explanation":"The yield of cocoa trees is influenced by factors such as pest infestation, fertilizer application, and the method of harvesting. However, the method of soil tilage does not directly influence the yield of cocoa trees. Soil tilage is the process of preparing the soil for planting by mechanical agitation, such as digging, stirring, and overturning. While it can affect the overall health of the soil and therefore the health of the plants growing in it, it does not directly affect the yield of cocoa trees.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>28","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : CLASSIFICATION OF CROPS","question":"The following crops are fibre crops except","images":[],"options":{"A":"cotton","B":"onion","C":"jute","D":"sisal"},"answer":"B","explanation":"Onion is not a fibre crop. Fibre crops are crops that are grown for their fibres, which are used in making textiles, ropes, and other products. Examples of fibre crops include cotton, jute, and sisal. Onions, on the other hand, are vegetable crops grown for their edible bulbs.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>29","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"The fencing and partitioning of a pastureland into paddocks is meant to","images":[],"options":{"A":"suppress weeds that compete with pasture crops","B":"control grazing and ensure regeneration of pasture","C":"allow free movement of ruminants on the pasture","D":"prevent lodging of the pasture plants."},"answer":"B","explanation":"The fencing and partitioning of a pastureland into paddick is meant to control grazing and ensure regeneration of pasture","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>30","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"When a gene is expressed in the phenotype in a homozygous form,that gene is said to be","images":[],"options":{"A":"segregating","B":"recessive","C":"dominant","D":"desirable"},"answer":"C","explanation":"In genetics, when a gene is expressed in the phenotype in a homozygous form, that gene is said to be dominant. A dominant gene is one that is expressed in the phenotype even when only one copy is present in the genotype. This is in contrast to a recessive gene, which is only expressed when two copies are present.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>31","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Uncontrolled burning of forests encourages","images":[],"options":{"A":"deforestation","B":"afforestation","C":"regenration","D":"exploitation"},"answer":"A","explanation":"Uncontrolled burning of forests encourages deforestation. Deforestation is the removal or clearing of forests, often to make way for agricultural activities or logging. Uncontrolled burning can quickly destroy large areas of forest, leading to loss of habitat, increased carbon dioxide levels in the atmosphere, and other negative environmental impacts.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>32","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Which of the following tree species is suitable for making electric poles?","images":[],"options":{"A":"Indian almond","B":"Mango","C":"Silk cotton","D":"Teak"},"answer":"D","explanation":"Teak is a type of hardwood that is commonly used for making electric poles. It is known for its durability and resistance to elements, which makes it suitable for outdoor use. The other options, Indian almond, Mango, and Silk cotton, are not typically used for this purpose.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>33","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"A pest that attacks stored maize grains is","images":[],"options":{"A":"mirids","B":"rodent","C":"grasshopper","D":"aphid"},"answer":"B","explanation":"A pest that attacks stored grains is rodent , other paste listed in the option with attack the maize before it is harvested","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>34","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"FORESTRY : AGRO-FORESTRY PRACTICES IN WEST AFRICA","question":"An agricultural system which combines crop production with forest establishment is known as","images":[],"options":{"A":"plantation farming","B":"taungya farming","C":"arable farming","D":"mixed farming"},"answer":"B","explanation":"Taungya farming is an agricultural system that combines crop production with forest establishment. It involves the cultivation of crops between young trees in a forest plantation until the trees become large enough to form a canopy. This system allows for efficient land use and provides both timber and agricultural produce. The other options, plantation farming, arable farming, and mixed farming, do not involve the combination of crop production with forest establishment.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>35","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"An important characteristics of pigs is that they are","images":[],"options":{"A":"highly prolific","B":"great milk producers","C":"resistant to parasites","D":"able to digest cellulose"},"answer":"A","explanation":"Pigs are known to be highly prolific, meaning they reproduce in large numbers. This is a significant characteristic of pigs that makes them a valuable livestock species. The other options are not accurate. Pigs are not great milk producers, they are not particularly resistant to parasites, and while they can digest a wide variety of food, they do not have the ability to digest cellulose like ruminants do.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>36","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"Digestion in ruminants is mainly","images":[],"options":{"A":"enzymatic","B":"microbial","C":"mastication and enzymatic","D":"microbial and enzymatic"},"answer":"D","explanation":"Digestion in ruminants is both microbial and enzymatic. Ruminants have a unique digestive system that includes a four-chambered stomach. The first chamber, the rumen, is filled with microbes that break down complex plant materials like cellulose. The other chambers involve enzymatic digestion. Therefore, the process is both microbial and enzymatic.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>37","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"If 30 eggs make up a crate of eggs, how many eggs are in 2packs  assuming a pack contains 10 crates of eggs?","images":[],"options":{"A":"200 eggs","B":"300 eggs","C":"400 eggs","D":"600 eggs"},"answer":"D","explanation":"1 pack = 10  crates of eggs   2 packs = x  x = 20 crates of eggs   30 eggs makes 1 crates   x eggs makes 20 crates ( 2 packs aaa)","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>38","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"In a brodder house, which of the following factors is monitored with the use of wet and dry hygrometer?","images":[],"options":{"A":"Rainfall","B":"Temperature","C":"Relative humidity","D":"Atmospheric presure"},"answer":"C","explanation":"In a brooder house, the wet and dry hygrometer is used to monitor the relative humidity. Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. It is important to maintain the right humidity levels in a brooder house to ensure the comfort and health of the chicks.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>39","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Which of the following statements is not a reason for feeding farm animals?","images":[],"options":{"A":"Production of energy for work","B":"Building up of body tissue","C":"production of inorganic manure","D":"Production of animals"},"answer":"C","explanation":"Feeding farm animals is not done for the production of inorganic manure. The primary reasons for feeding farm animals are to provide energy for work, build up body tissue, and for the production of more animals. While manure is a byproduct of feeding animals, it is organic, not inorganic.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>40","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Rickets in farm animals can be controlled by","images":[],"options":{"A":"Feeding carbohydrates to the animals","B":"feeding animals with quality grasses and legumes","C":"adding yeast and vegetables and animal feed.","D":"adding fish meal and oyster shell to animal feed."},"answer":"D","explanation":"Rickets in farm animals can be controlled by adding fish meal and oyster shell to animal feed. Rickets is a disease caused by a deficiency in vitamin D, calcium, or phosphate. Fish meal and oyster shells are rich in these nutrients, hence their addition to animal feed can help prevent or control rickets.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>41","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : RANGELAND AND PASTURE MANAGEMENT","question":"The methods of rangeland improvement which ensures continuous  herbage growth during the dry season are","images":[],"options":{"A":"reseeding and pest control","B":"controlled stocking and disease control","C":"fertilizer application and irrigation","D":"rotational grazing and weed control"},"answer":"C","explanation":"Fertilization application and irrigation are methods of rangeland improvement which ensures continous herbage growth during the dry season","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>42","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Tapeworm, liver fluke and roundworm can be controlled by","images":[],"options":{"A":"flushing","B":"drenching","C":"dipping","D":"fumigation"},"answer":"B","explanation":"Drenching is the process of adminstering medicine to a farm animals to kill internal parasites or endoparasites.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>43","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"The part which a bait is attached before lowering the tool in water is labelled","images":["data:image/png;base64,"],"options":{"A":"IV","B":"III","C":"II","D":"I"},"answer":"D","explanation":"The part labelled I (hook) is the part which a bait is attached before lowering the tool in water.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>44","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Which of the labelled parts enables the tool to float on water when fish is caught","images":["data:image/png;base64,"],"options":{"A":"IV","B":"III","C":"II","D":"I"},"answer":"C","explanation":"The part labelled II enables the tool to float on water when fish is caught.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>45","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"ANIMAL PRODUCTION : APICULTURE OR BEE KEEPING","question":"Which of the following statements is not a precautionary measure in the bee keeping?","images":[],"options":{"A":"The apiary should not be fenced to allow for proper ventilation","B":"The attendant should always wear protective clothing","C":"Warning signs should be placed near the apiary","D":"Locate apiaries far from human dwellings"},"answer":"A","explanation":"The apiary should be fenced to protect the bees from predators and to prevent them from straying. Fencing does not interfere with ventilation as bees can fly over the fence. The other options are correct precautionary measures in beekeeping.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>46","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL FINANCE","question":"If a farmer produces 9 bags of millet at an average cost of D 80,000.00 per bags and sells each of the 9 bags at D 90,000.00, the profit is","images":[],"options":{"A":"D 10,000.00","B":"D 80,000.00","C":"D 90,000.00","D":"D 170,000.00"},"answer":"C","explanation":"Cost price = 9x 80000 = D720,000  Selleing price = 9 x 900000 = D810,000  Profit = s.p - c.p = D90,000","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>47","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"The part labelled C in the graph is the","images":["data:image/png;base64,"],"options":{"A":"quantity supplied","B":"equilibrium price","C":"quantity demanded","D":"equilibrium point."},"answer":"D","explanation":"The part labelled C in the graph is the equilibriu point equilibrium point in which forces are balanced where the current prices stabilizes between even supply demand .","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2020>48","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF SUPPLY","question":"A farmer whose production exceeds point C will experience","images":["data:image/png;base64,"],"options":{"A":"surplus to the market","B":"shortfalls in supply","C":"decrease in cost of production","D":"decrease in revenue generation"},"answer":"A","explanation":"A farmer whoses production exceeds point C will experience surpus to market","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2020>49","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"A total of 12000 kg of maize was demanded at \u20a620 per Kg while 8000kg of it was demanded at \u20a630 per kg. What is the percentage change in quantity demanded?","images":[],"options":{"A":"33%","B":"50%","C":"67%","D":"150%"},"answer":"A","explanation":"The percentage change in quantity demanded is calculated by subtracting the final quantity from the initial quantity, dividing the result by the initial quantity, and then multiplying by 100. In this case, the initial quantity is 12000 kg and the final quantity is 8000 kg. So, the percentage change is ((12000 - 8000) / 12000) * 100 = 33.33%, which is approximately 33%. Therefore, the correct option is 1.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2020>50","subject":"Agricultural Science","year":"2020","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"A cost effective way of disseminating urgent information to a large number of farmers at the same time is through","images":[],"options":{"A":"demonstration","B":"evaluation","C":"mass media","D":"field trip"},"answer":"C","explanation":"Mass media is a cost effective way of disseminating urget information to a large  number at th same time","marks":"1","difficulty":"2"}];